const input = $('Input (editar antes de ejecutar)').first().json;
const chatsRaw = $('Listar chats Evolution').first().json;
const optOutsRaw = $('Listar opt-outs').all();

// Evolution API can return an array directly or wrap it in {chats: [...]}; normalize.
let chatList = [];
if (Array.isArray(chatsRaw)) {
  chatList = chatsRaw;
} else if (Array.isArray(chatsRaw?.chats)) {
  chatList = chatsRaw.chats;
} else if (Array.isArray(chatsRaw?.data)) {
  chatList = chatsRaw.data;
}

const optOutSet = new Set();
for (const it of optOutsRaw) {
  const j = it.json;
  if (Array.isArray(j)) {
    for (const row of j) if (row.phone_number) optOutSet.add(row.phone_number);
  } else if (j?.phone_number) {
    optOutSet.add(j.phone_number);
  }
}

const totalChats = chatList.length;
let excludedGroups = 0;
let excludedOptOuts = 0;
const recipients = [];
const seen = new Set();

for (const chat of chatList) {
  const remoteJid = chat.remoteJid || chat.id || '';
  if (!remoteJid) continue;
  if (remoteJid.endsWith('@g.us') || remoteJid.endsWith('@lid') || remoteJid === 'status@broadcast') {
    excludedGroups++;
    continue;
  }
  const phoneNumber = remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '').replace('@lid', '');
  if (!phoneNumber) continue;
  if (seen.has(phoneNumber)) continue;
  seen.add(phoneNumber);
  if (optOutSet.has(phoneNumber)) {
    excludedOptOuts++;
    continue;
  }
  recipients.push({
    json: {
      phoneNumber,
      pushName: chat.pushName || chat.name || '',
      media_url: input.media_url,
      media_type: input.media_type,
      caption: input.caption,
      _meta: { totalChats, excludedGroups, excludedOptOuts }
    }
  });
}

if (recipients.length === 0) {
  return [{
    json: {
      _no_recipients: true,
      totalChats,
      excludedGroups,
      excludedOptOuts
    }
  }];
}

return recipients;

const items = $input.all();
const filter = $('Filtrar destinatarios').first().json || {};
const meta = filter._meta || {};

// If the filter produced the no-recipients sentinel, items[0] will carry it.
if (filter._no_recipients || items[0]?.json?._no_recipients) {
  return [{
    json: {
      status: 'no_recipients',
      total_chats: filter.totalChats ?? items[0]?.json?.totalChats ?? 0,
      groups_excluidos: filter.excludedGroups ?? items[0]?.json?.excludedGroups ?? 0,
      opt_outs_excluidos: filter.excludedOptOuts ?? items[0]?.json?.excludedOptOuts ?? 0,
      enviados_ok: 0,
      enviados_error: 0,
      mensaje: 'No hay destinatarios elegibles.'
    }
  }];
}

let ok = 0;
let err = 0;
for (const it of items) {
  const j = it.json || {};
  const isError = j.error || j.status === 'error' || (typeof j.statusCode === 'number' && j.statusCode >= 400);
  if (isError) err++;
  else ok++;
}

return [{
  json: {
    status: 'done',
    total_chats: meta.totalChats ?? 0,
    groups_excluidos: meta.excludedGroups ?? 0,
    opt_outs_excluidos: meta.excludedOptOuts ?? 0,
    enviados_ok: ok,
    enviados_error: err,
    total_procesados: items.length
  }
}];
